 1→import { useRef, useCallback, useMemo } from "react";
 2→import { useScrollToSelected } from "../hooks/useScrollToSelected";
 3→import type { DisplayMessage } from "../types";
 4→import { MessageItem } from "./MessageItem";
 5→
 6→interface MessageListProps {
 7→  messages: DisplayMessage[];
 8→  selectedIndex: number;
 9→  expandedSet: Set<number>;
10→  ongoing: boolean;
11→  onSelect: (index: number) => void;
12→  onToggle: (index: number) => void;
13→  onOpenDetail: (index: number) => void;
14→}
15→
16→export function MessageList({
17→  messages,
18→  selectedIndex,
19→  expandedSet,
20→  ongoing,
21→  onSelect,
22→  onToggle,
23→  onOpenDetail,
24→}: MessageListProps) {
25→  const listRef = useRef<HTMLDivElement>(null);
26→  const selectedRef = useScrollToSelected(selectedIndex);
27→
28→  const handleClick = useCallback(
29→    (index: number) => {
30→      if (selectedIndex === index) {
31→        onToggle(index);
32→      } else {
33→        onSelect(index);
34→      }
35→    },
36→    [selectedIndex, onSelect, onToggle],
37→  );
38→
39→  // Chronological order: oldest messages first
40→  const ordered = useMemo(() => {
41→    const indices: number[] = [];
42→    for (let i = 0; i < messages.length; i++) {
43→      indices.push(i);
44→    }
45→    return indices;
46→  }, [messages.length]);
47→
48→  if (messages.length === 0) {
49→    return (
50→      <div className="message-list">
51→        <div className="message-list__empty">No messages loaded</div>
52→      </div>
53→    );
54→  }
55→
56→  return (
57→    <div className="message-list" ref={listRef}>
58→      {ordered.map((i) => {
59→        const msg = messages[i];
60→        if (msg.role === "compact") {
61→          return <CompactSeparator key={i} content={msg.content} />;
62→        }
63→
64→        const isSelected = i === selectedIndex;
65→        const isLast = i === messages.length - 1;
66→
67→        return (
68→          <MessageItem
69→            key={i}
70→            ref={isSelected ? selectedRef : undefined}
71→            message={msg}
72→            index={i}
73→            isSelected={isSelected}
74→            isExpanded={expandedSet.has(i)}
75→            onClick={handleClick}
76→            onOpenDetail={onOpenDetail}
77→            isOngoing={isLast && ongoing}
78→          />
79→        );
80→      })}
81→    </div>
82→  );
83→}
84→
85→function CompactSeparator({ content }: { content: string }) {
86→  return (
87→    <div className="compact-separator">
88→      <div className="compact-separator__line">
89→        <span className="compact-separator__rule" />
90→        <span>{content}</span>
91→        <span className="compact-separator__rule" />
92→      </div>
93→    </div>
94→  );
95→}
