  1→import type { DisplayMessage } from "../types";
  2→import { shortModel, formatExactTime, firstLine, truncate } from "../lib/format";
  3→import { getModelColor } from "../lib/theme";
  4→import { StatsBar, statsFromMessage } from "./StatsBar";
  5→import { ClaudeIcon, UserIcon, SystemIcon, WarningIcon, ForwardIcon } from "./Icons";
  6→import { OngoingDots } from "./OngoingDots";
  7→
  8→interface MessageItemProps {
  9→  message: DisplayMessage;
 10→  index: number;
 11→  isSelected: boolean;
 12→  isExpanded: boolean;
 13→  onClick: (index: number) => void;
 14→  onOpenDetail: (index: number) => void;
 15→  /** Whether this message is currently being processed */
 16→  isOngoing?: boolean;
 17→  ref?: React.Ref<HTMLDivElement>;
 18→}
 19→
 20→export function MessageItem({
 21→  ref,
 22→  message: msg,
 23→  index,
 24→  isSelected,
 25→  isExpanded,
 26→  onClick,
 27→  onOpenDetail,
 28→  isOngoing,
 29→}: MessageItemProps) {
 30→  const roleClass =
 31→    msg.role === "user"
 32→      ? "message--user"
 33→      : msg.role === "claude"
 34→        ? "message--claude"
 35→        : msg.is_error
 36→          ? "message--system-error"
 37→          : "message--system";
 38→
 39→  const model = msg.model ? shortModel(msg.model) : "";
 40→  const modelColor = msg.model ? getModelColor(msg.model) : undefined;
 41→  const time = formatExactTime(msg.timestamp);
 42→  const contentPreview = isExpanded ? msg.content : truncate(firstLine(msg.content), 200);
 43→  const stats = statsFromMessage(msg);
 44→
 45→  return (
 46→    <div
 47→      ref={ref}
 48→      className={`message ${roleClass}${isSelected ? " message--selected" : ""}`}
 49→      onClick={() => onClick(index)}
 50→      onDoubleClick={() => onOpenDetail(index)}
 51→    >
 52→      <div className="message__header">
 53→        <span className="message__role-icon">
 54→          {msg.role === "claude" ? (
 55→            <ClaudeIcon className="message__claude-icon" />
 56→          ) : msg.role === "user" ? (
 57→            <UserIcon />
 58→          ) : msg.is_error ? (
 59→            <WarningIcon />
 60→          ) : (
 61→            <SystemIcon />
 62→          )}
 63→        </span>
 64→        <span
 65→          className={`message__role message__role--${msg.role === "claude" ? "claude" : msg.role === "user" ? "user" : "system"}`}
 66→        >
 67→          {msg.role === "user" ? "User" : msg.role === "claude" ? "Claude" : "System"}
 68→        </span>
 69→        {model && (
 70→          <span className="message__model" style={{ color: modelColor }}>
 71→            {model}
 72→          </span>
 73→        )}
 74→        {msg.subagent_label && (
 75→          <span className="detail-item__subagent-badge">{msg.subagent_label}</span>
 76→        )}
 77→        {time && <span className="message__timestamp">{time}</span>}
 78→        {isOngoing && <OngoingDots />}
 79→        {(msg.items.length > 0 || msg.tool_call_count > 0 || msg.thinking_count > 0) && (
 80→          <button
 81→            className="message__detail-btn"
 82→            onClick={(e) => {
 83→              e.stopPropagation();
 84→              onOpenDetail(index);
 85→            }}
 86→          >
 87→            Detail <ForwardIcon />
 88→          </button>
 89→        )}
 90→      </div>
 91→
 92→      <div className={`message__content${!isExpanded ? " message__content--collapsed" : ""}`}>
 93→        {contentPreview}
 94→      </div>
 95→
 96→      <StatsBar stats={stats} />
 97→    </div>
 98→  );
 99→}
