 1→import { useRef, useEffect } from "react";
 2→
 3→export function useScrollToSelected(dep: number) {
 4→  const ref = useRef<HTMLDivElement>(null);
 5→  useEffect(() => {
 6→    ref.current?.scrollIntoView({ block: "nearest" });
 7→  }, [dep]);
 8→  return ref;
 9→}
