  1→import { useState, useEffect, useCallback, useRef } from "react";
  2→import { invoke } from "@tauri-apps/api/core";
  3→import type { ViewState, SessionInfo } from "./types";
  4→import { useSession } from "./hooks/useSession";
  5→import { usePicker } from "./hooks/usePicker";
  6→import { useToggleSet } from "./hooks/useToggleSet";
  7→import { useKeyboard } from "./hooks/useKeyboard";
  8→import { SessionPicker } from "./components/SessionPicker";
  9→import { MessageList } from "./components/MessageList";
 10→import { MessageDetail } from "./components/MessageDetail";
 11→import { TeamBoard } from "./components/TeamBoard";
 12→import { DebugViewer } from "./components/DebugViewer";
 13→import { InfoBar } from "./components/InfoBar";
 14→import { KeybindBar } from "./components/KeybindBar";
 15→import { ViewToolbar } from "./components/ViewToolbar";
 16→import { ProjectTree, useProjectKeys } from "./components/ProjectTree";
 17→import { ResizeHandle } from "./components/ResizeHandle";
 18→import { SettingsModal } from "./components/SettingsModal";
 19→
 20→export function App() {
 21→  const [view, setView] = useState<ViewState>("picker");
 22→  const [selectedMessage, setSelectedMessage] = useState(0);
 23→  const [pickerSelectedIndex, setPickerSelectedIndex] = useState(0);
 24→  const [showKeybinds, setShowKeybinds] = useState(true);
 25→  const [animFrame, setAnimFrame] = useState(0);
 26→  const [selectedProject, setSelectedProject] = useState<string | null>(null);
 27→  const [sidebarWidth, setSidebarWidth] = useState(180);
 28→  const [sidebarFocused, setSidebarFocused] = useState(false);
 29→  const [sidebarHighlight, setSidebarHighlight] = useState(0); // index in project list (0 = "All")
 30→  const [showSettings, setShowSettings] = useState(false);
 31→
 32→  const handleSelectProject = useCallback(
 33→    (project: string | null) => {
 34→      setSelectedProject(project);
 35→      setPickerSelectedIndex(0);
 36→      setSidebarFocused(false);
 37→      if (view !== "picker") setView("picker");
 38→    },
 39→    [view],
 40→  );
 41→
 42→  const session = useSession();
 43→  const picker = usePicker(selectedProject);
 44→  const projectKeys = useProjectKeys(picker.allSessions);
 45→
 46→  const { loadSession, loadDebugLog, sessionPath } = session;
 47→  const { discoverSessions } = picker;
 48→
 49→  const {
 50→    set: expandedMessages,
 51→    toggle: toggleMessage,
 52→    clear: clearExpanded,
 53→    addAll: expandMessages,
 54→  } = useToggleSet();
 55→
 56→  // Animation frame for ongoing indicators
 57→  useEffect(() => {
 58→    if (!session.ongoing) return;
 59→    const id = setInterval(() => {
 60→      setAnimFrame((f) => f + 1);
 61→    }, 100);
 62→    return () => clearInterval(id);
 63→  }, [session.ongoing]);
 64→
 65→  // Sync session ongoing state to picker tree
 66→  useEffect(() => {
 67→    if (session.sessionPath) {
 68→      picker.syncOngoing(session.sessionPath, session.ongoing);
 69→    }
 70→  }, [session.ongoing, session.sessionPath, picker]);
 71→
 72→  // Shared: fetch project dirs and discover sessions
 73→  const loadProjectDirs = useCallback(async () => {
 74→    try {
 75→      const dirs = await invoke<string[]>("get_project_dirs");
 76→      if (dirs.length > 0) {
 77→        discoverSessions(dirs);
 78→      }
 79→    } catch (err) {
 80→      console.error("Failed to get project dirs:", err);
 81→    }
 82→  }, [discoverSessions]);
 83→
 84→  // Auto-discover sessions on mount; show settings if no path configured
 85→  const discoveredRef = useRef(false);
 86→  useEffect(() => {
 87→    if (discoveredRef.current) return;
 88→    discoveredRef.current = true;
 89→    const discover = async () => {
 90→      let hasConfig = false;
 91→      try {
 92→        const settings = await invoke<{ projects_dir: string | null }>("get_settings");
 93→        hasConfig = settings.projects_dir != null;
 94→      } catch {
 95→        // no settings file yet
 96→      }
 97→      if (!hasConfig) {
 98→        setShowSettings(true);
 99→        return;
100→      }
101→      loadProjectDirs();
102→    };
103→    discover();
104→  }, [loadProjectDirs]);
105→
106→  // Handle session selection from picker
107→  const handleSelectSession = useCallback(
108→    (sessionInfo: SessionInfo) => {
109→      loadSession(sessionInfo.path);
110→      setView("list");
111→      setSelectedMessage(0);
112→      clearExpanded();
113→    },
114→    [loadSession, clearExpanded],
115→  );
116→
117→  // Auto-select newest message (last index) when messages load
118→  useEffect(() => {
119→    if (session.messages.length > 0 && view === "list") {
120→      setSelectedMessage((prev) =>
121→        prev >= session.messages.length ? session.messages.length - 1 : prev,
122→      );
123→    }
124→  }, [session.messages.length, view]);
125→
126→  // Open detail view
127→  const openDetail = useCallback((index: number) => {
128→    setSelectedMessage(index);
129→    setView("detail");
130→  }, []);
131→
132→  // -- Extracted action callbacks for toolbar + keyboard --
133→
134→  const expandAll = useCallback(() => {
135→    const claudeIndices: number[] = [];
136→    session.messages.forEach((msg, i) => {
137→      if (msg.role === "claude") claudeIndices.push(i);
138→    });
139→    expandMessages(claudeIndices);
140→  }, [session.messages, expandMessages]);
141→
142→  const collapseAll = useCallback(() => {
143→    clearExpanded();
144→  }, [clearExpanded]);
145→
146→  // Visual top = newest message = last index (display is reversed)
147→  const jumpToTop = useCallback(() => {
148→    setSelectedMessage(Math.max(session.messages.length - 1, 0));
149→  }, [session.messages.length]);
150→
151→  // Visual bottom = oldest message = index 0
152→  const jumpToBottom = useCallback(() => {
153→    setSelectedMessage(0);
154→  }, []);
155→
156→  const openDebug = useCallback(() => {
157→    if (sessionPath) {
158→      loadDebugLog(sessionPath);
159→      setView("debug");
160→    }
161→  }, [sessionPath, loadDebugLog]);
162→
163→  const openTeams = useCallback(() => {
164→    if (session.teams.length > 0) setView("team");
165→  }, [session.teams.length]);
166→
167→  const goToSessions = useCallback(() => {
168→    setView("picker");
169→  }, []);
170→
171→  const backToList = useCallback(() => {
172→    if (sessionPath) setView("list");
173→  }, [sessionPath]);
174→
175→  const toggleKeybinds = useCallback(() => {
176→    setShowKeybinds((v) => !v);
177→  }, []);
178→
179→  const selectProjectByIndex = useCallback(
180→    (index: number) => {
181→      if (index >= 0 && index < projectKeys.length) {
182→        handleSelectProject(projectKeys[index]);
183→      }
184→    },
185→    [projectKeys, handleSelectProject],
186→  );
187→
188→  // Keyboard navigation — build keyMap per view
189→  const keyMap: Record<string, () => void> = {};
190→
191→  // Sidebar-focused shortcuts (override main shortcuts when sidebar has focus)
192→  if (sidebarFocused) {
193→    const sidebarDown = () => setSidebarHighlight((i) => Math.min(i + 1, projectKeys.length - 1));
194→    const sidebarUp = () => setSidebarHighlight((i) => Math.max(i - 1, 0));
195→    keyMap["j"] = sidebarDown;
196→    keyMap["ArrowDown"] = sidebarDown;
197→    keyMap["k"] = sidebarUp;
198→    keyMap["ArrowUp"] = sidebarUp;
199→    keyMap["Enter"] = () => selectProjectByIndex(sidebarHighlight);
200→    keyMap["Escape"] = () => setSidebarFocused(false);
201→    keyMap["l"] = () => setSidebarFocused(false);
202→    keyMap["ArrowRight"] = () => setSidebarFocused(false);
203→    keyMap["?"] = toggleKeybinds;
204→  } else {
205→    switch (view) {
206→      case "list": {
207→        const listDown = () => setSelectedMessage((i) => Math.max(i - 1, 0));
208→        const listUp = () =>
209→          setSelectedMessage((i) => Math.min(i + 1, session.messages.length - 1));
210→        keyMap["j"] = listDown;
211→        keyMap["ArrowDown"] = listDown;
212→        keyMap["k"] = listUp;
213→        keyMap["ArrowUp"] = listUp;
214→        keyMap["G"] = jumpToTop;
215→        keyMap["g"] = jumpToBottom;
216→        keyMap["Tab"] = () => toggleMessage(selectedMessage);
217→        keyMap["Enter"] = () => {
218→          if (session.messages.length > 0) openDetail(selectedMessage);
219→        };
220→        keyMap["e"] = expandAll;
221→        keyMap["c"] = collapseAll;
222→        keyMap["t"] = openTeams;
223→        keyMap["d"] = openDebug;
224→        keyMap["q"] = goToSessions;
225→        keyMap["Escape"] = goToSessions;
226→        keyMap["s"] = goToSessions;
227→        keyMap["?"] = toggleKeybinds;
228→        keyMap["h"] = () => setSidebarFocused(true);
229→        keyMap["ArrowLeft"] = () => setSidebarFocused(true);
230→        break;
231→      }
232→      case "detail":
233→        // j/k/Tab/Enter/q/Escape handled by MessageDetail's own useKeyboard
234→        keyMap["?"] = toggleKeybinds;
235→        break;
236→      case "picker": {
237→        const pickerDown = () =>
238→          setPickerSelectedIndex((i) => Math.min(i + 1, picker.sessions.length - 1));
239→        const pickerUp = () => setPickerSelectedIndex((i) => Math.max(i - 1, 0));
240→        keyMap["j"] = pickerDown;
241→        keyMap["ArrowDown"] = pickerDown;
242→        keyMap["k"] = pickerUp;
243→        keyMap["ArrowUp"] = pickerUp;
244→        keyMap["Enter"] = () => {
245→          if (picker.sessions[pickerSelectedIndex])
246→            handleSelectSession(picker.sessions[pickerSelectedIndex]);
247→        };
248→        keyMap["q"] = backToList;
249→        keyMap["Escape"] = backToList;
250→        keyMap["?"] = toggleKeybinds;
251→        keyMap["h"] = () => setSidebarFocused(true);
252→        keyMap["ArrowLeft"] = () => setSidebarFocused(true);
253→        break;
254→      }
255→      case "team":
256→        keyMap["q"] = () => setView("list");
257→        keyMap["Escape"] = () => setView("list");
258→        keyMap["?"] = toggleKeybinds;
259→        break;
260→      case "debug":
261→        keyMap["q"] = () => setView("list");
262→        keyMap["Escape"] = () => setView("list");
263→        keyMap["?"] = toggleKeybinds;
264→        break;
265→    }
266→  }
267→  useKeyboard(keyMap);
268→
269→  // Keybind bar click actions
270→  const keybindActions: Record<string, () => void> = {};
271→  if (view === "list") {
272→    keybindActions["debug"] = openDebug;
273→    keybindActions["sessions"] = goToSessions;
274→    if (session.teams.length > 0) {
275→      keybindActions["tasks"] = openTeams;
276→    }
277→  } else if (view === "picker") {
278→    keybindActions["back"] = backToList;
279→  } else if (view === "detail") {
280→    keybindActions["back"] = () => setView("list");
281→  } else if (view === "team") {
282→    keybindActions["back"] = () => setView("list");
283→  } else if (view === "debug") {
284→    keybindActions["back"] = () => setView("list");
285→  }
286→
287→  // Render the active view
288→  const renderView = () => {
289→    switch (view) {
290→      case "picker":
291→        return (
292→          <SessionPicker
293→            sessions={picker.sessions}
294→            loading={picker.loading}
295→            searchQuery={picker.searchQuery}
296→            selectedIndex={pickerSelectedIndex}
297→            onSelect={handleSelectSession}
298→            onSearchChange={picker.setSearchQuery}
299→            onSelectIndex={setPickerSelectedIndex}
300→            animFrame={animFrame}
301→          />
302→        );
303→
304→      case "list":
305→        return (
306→          <MessageList
307→            messages={session.messages}
308→            selectedIndex={selectedMessage}
309→            expandedSet={expandedMessages}
310→            ongoing={session.ongoing}
311→            onSelect={setSelectedMessage}
312→            onToggle={toggleMessage}
313→            onOpenDetail={openDetail}
314→          />
315→        );
316→
317→      case "detail":
318→        if (session.messages.length > 0 && selectedMessage < session.messages.length) {
319→          return (
320→            <MessageDetail
321→              message={session.messages[selectedMessage]}
322→              ongoing={session.ongoing}
323→              onBack={() => setView("list")}
324→            />
325→          );
326→        }
327→        return null;
328→
329→      case "team":
330→        return <TeamBoard teams={session.teams} onBack={() => setView("list")} />;
331→
332→      case "debug":
333→        return <DebugViewer entries={session.debugEntries} onBack={() => setView("list")} />;
334→    }
335→  };
336→
337→  return (
338→    <div className="app">
339→      {/* Info bar — only show when we have a loaded session */}
340→      {session.sessionPath && view !== "picker" && (
341→        <InfoBar
342→          meta={session.meta}
343→          gitInfo={session.gitInfo}
344→          messages={session.messages}
345→          sessionTotals={session.sessionTotals}
346→          sessionPath={session.sessionPath}
347→          ongoing={session.ongoing}
348→          animFrame={animFrame}
349→        />
350→      )}
351→
352→      {/* View toolbar */}
353→      <ViewToolbar
354→        view={view}
355→        hasTeams={session.teams.length > 0}
356→        hasSession={!!session.sessionPath}
357→        messageCount={session.messages.length}
358→        onGoToSessions={goToSessions}
359→        onExpandAll={expandAll}
360→        onCollapseAll={collapseAll}
361→        onJumpTop={jumpToTop}
362→        onJumpBottom={jumpToBottom}
363→        onOpenTeams={openTeams}
364→        onOpenDebug={openDebug}
365→        onBackToList={backToList}
366→        onOpenSettings={() => setShowSettings(true)}
367→      />
368→
369→      <div className="app-body">
370→        <ProjectTree
371→          sessions={picker.allSessions}
372→          selectedProject={selectedProject}
373→          highlightedIndex={sidebarHighlight}
374→          isFocused={sidebarFocused}
375→          onSelectProject={handleSelectProject}
376→          onRefresh={loadProjectDirs}
377→          onFocus={() => setSidebarFocused(true)}
378→          refreshing={picker.loading}
379→          style={{ width: sidebarWidth, minWidth: 100, maxWidth: 400 }}
380→        />
381→        <ResizeHandle onResize={setSidebarWidth} />
382→        <div className="main-content" onClick={() => setSidebarFocused(false)}>
383→          {renderView()}
384→        </div>
385→      </div>
386→
387→      {/* Keybind bar */}
388→      <KeybindBar
389→        view={view}
390→        hasTeams={session.teams.length > 0}
391→        showHints={showKeybinds}
392→        onToggle={toggleKeybinds}
393→        actions={keybindActions}
394→      />
395→
396→      {showSettings && (
397→        <SettingsModal onClose={() => setShowSettings(false)} onSaved={loadProjectDirs} />
398→      )}
399→    </div>
400→  );
401→}
