 17→/* ─── Panel stack types ─── */
 18→
 19→type PanelEntry =
 20→  | { kind: "agent-list"; item: DisplayItem; key: string }
 21→  | { kind: "agent-detail"; item: DisplayItem; msg: DisplayMessage; key: string };
 22→
 23→/** Imperative handle exposed by each navigable column */
 24→interface ColumnNav {
 25→  moveUp: () => void;
 26→  moveDown: () => void;
 27→  toggle: () => void;
 28→  enter: () => void;
 29→  itemCount: () => number;
 30→}
 31→
 32→interface MessageDetailProps {
 33→  message: DisplayMessage;
 34→  ongoing?: boolean;
 35→  onBack: () => void;
 36→}
 37→
 38→export function MessageDetail({ message: msg, ongoing, onBack }: MessageDetailProps) {
 39→  const { set: expandedItems, toggle: toggleItem } = useToggleSet();
 40→  const [selectedItem, setSelectedItem] = useState(0);
 41→  const scrollRef = useScrollToSelected(selectedItem);
 42→  const [panelStack, setPanelStack] = useState<PanelEntry[]>([]);
 43→  const [columnWidths, setColumnWidths] = useState<(number | null)[]>([null]);
 44→  const [focusedColumn, setFocusedColumn] = useState(0); // 0 = main, 1+ = panel index + 1
 45→  const bodyRef = useRef<HTMLDivElement>(null);
 46→  const savedScroll = useRef<number | null>(null);
 47→  const panelRefs = useRef<Map<number, ColumnNav>>(new Map());
 48→
 49→  useLayoutEffect(() => {
 50→    if (savedScroll.current != null && bodyRef.current) {
 51→      bodyRef.current.scrollTop = savedScroll.current;
 52→      savedScroll.current = null;
 53→    }
 54→  }, [panelStack.length]);
 55→
 56→  const model = msg.model ? shortModel(msg.model) : "";
 57→  const modelColor = msg.model ? getModelColor(msg.model) : undefined;
 58→  const time = formatExactTime(msg.timestamp);
 59→  const hasItems = msg.items.length > 0;
 60→  const hasPanels = panelStack.length > 0;
 61→
 62→  // Stack manipulation
 63→  const openSubagentFromMain = useCallback((item: DisplayItem) => {
 64→    if (bodyRef.current) {
 65→      savedScroll.current = bodyRef.current.scrollTop;
 66→    }
 67→    setPanelStack((prev) => {
 68→      if (
 69→        prev.length === 1 &&
 70→        prev[0].kind === "agent-list" &&
 71→        prev[0].item.agent_id === item.agent_id
 72→      ) {
 73→        return [];
 74→      }
 75→      return [{ kind: "agent-list", item, key: item.agent_id || `panel-0` }];
 76→    });
 77→    setColumnWidths((prev) => [prev[0]]);
 78→    setFocusedColumn(1);
 79→  }, []);
 80→
 81→  const openSubagentAt = useCallback((depth: number, item: DisplayItem) => {
 82→    setPanelStack((prev) => {
 83→      const next = prev.slice(0, depth + 1);
 84→      next.push({ kind: "agent-list", item, key: item.agent_id || `panel-${depth + 1}` });
 85→      return next;
 86→    });
 87→    setColumnWidths((prev) => prev.slice(0, depth + 2));
 88→    setFocusedColumn(depth + 2);
 89→  }, []);
 90→
 91→  const openDetailAt = useCallback((depth: number, detailMsg: DisplayMessage) => {
 92→    setPanelStack((prev) => {
 93→      const entry = prev[depth];
 94→      if (!entry || entry.kind !== "agent-list") return prev;
 95→      const next = prev.slice(0, depth);
 96→      next.push({
 97→        kind: "agent-detail",
 98→        item: entry.item,
 99→        msg: detailMsg,
100→        key: entry.key + ":detail",
101→      });
102→      return next;
103→    });
104→  }, []);
105→
106→  const backToListAt = useCallback((depth: number) => {
107→    setPanelStack((prev) => {
108→      const entry = prev[depth];
109→      if (!entry || entry.kind !== "agent-detail") return prev;
110→      const next = prev.slice(0, depth);
111→      next.push({
112→        kind: "agent-list",
113→        item: entry.item,
114→        key: entry.item.agent_id || `panel-${depth}`,
115→      });
116→      return next;
117→    });
118→  }, []);
119→
120→  const closeAt = useCallback((depth: number) => {
121→    setPanelStack((prev) => prev.slice(0, depth));
122→    setColumnWidths((prev) => prev.slice(0, depth + 1));
123→    setFocusedColumn((prev) => Math.min(prev, depth));
124→  }, []);
125→
126→  const setColumnWidth = useCallback((colIndex: number, width: number) => {
127→    setColumnWidths((prev) => {
128→      const next = [...prev];
129→      while (next.length <= colIndex) next.push(null);
130→      next[colIndex] = width;
131→      return next;
132→    });
133→  }, []);
134→
135→  const handleItemClick = (index: number, item: DisplayItem) => {
136→    setSelectedItem(index);
137→    setFocusedColumn(0);
138→    if (item.subagent_messages.length > 0) {
139→      openSubagentFromMain(item);
140→    } else {
141→      toggleItem(index);
142→    }
143→  };
144→
145→  const registerPanelNav = useCallback((depth: number, nav: ColumnNav | null) => {
146→    if (nav) {
147→      panelRefs.current.set(depth, nav);
148→    } else {
149→      panelRefs.current.delete(depth);
150→    }
151→  }, []);
152→
153→  // Single keyboard handler for all columns
154→  const detailKeyMap: Record<string, () => void> = {};
155→
156→  // Navigation: j/k/ArrowDown/ArrowUp/Tab/Enter dispatch to the focused column
157→  const moveDown = () => {
158→    if (focusedColumn === 0) {
159→      setSelectedItem((i) => Math.min(i + 1, msg.items.length - 1));
160→    } else {
161→      const nav = panelRefs.current.get(focusedColumn - 1);
162→      nav?.moveDown();
163→    }
164→  };
165→  const moveUp = () => {
166→    if (focusedColumn === 0) {
167→      setSelectedItem((i) => Math.max(i - 1, 0));
168→    } else {
169→      const nav = panelRefs.current.get(focusedColumn - 1);
170→      nav?.moveUp();
171→    }
172→  };
173→  detailKeyMap["j"] = moveDown;
174→  detailKeyMap["ArrowDown"] = moveDown;
175→  detailKeyMap["k"] = moveUp;
176→  detailKeyMap["ArrowUp"] = moveUp;
177→  detailKeyMap["Tab"] = () => {
178→    if (focusedColumn === 0) {
179→      const item = msg.items[selectedItem];
180→      if (item) handleItemClick(selectedItem, item);
181→    } else {
182→      const nav = panelRefs.current.get(focusedColumn - 1);
183→      nav?.toggle();
184→    }
185→  };
186→  detailKeyMap["Enter"] = () => {
187→    if (focusedColumn === 0) {
188→      const item = msg.items[selectedItem];
189→      if (item && item.subagent_messages.length > 0) {
190→        openSubagentFromMain(item);
191→      } else if (item) {
192→        toggleItem(selectedItem);
193→      }
194→    } else {
195→      const nav = panelRefs.current.get(focusedColumn - 1);
196→      nav?.enter();
197→    }
198→  };
199→
200→  // h/l or ArrowLeft/ArrowRight to switch focused column
201→  detailKeyMap["h"] = () => setFocusedColumn((c) => Math.max(0, c - 1));
202→  detailKeyMap["ArrowLeft"] = () => setFocusedColumn((c) => Math.max(0, c - 1));
203→  detailKeyMap["l"] = () => setFocusedColumn((c) => Math.min(panelStack.length, c + 1));
204→  detailKeyMap["ArrowRight"] = () => setFocusedColumn((c) => Math.min(panelStack.length, c + 1));
205→
206→  // q = go back to list
207→  detailKeyMap["q"] = onBack;
208→  // Escape = close rightmost panel, or go back
209→  detailKeyMap["Escape"] = () => {
210→    if (panelStack.length > 0) {
211→      closeAt(panelStack.length - 1);
212→    } else {
213→      onBack();
214→    }
215→  };
216→
217→  useKeyboard(detailKeyMap);
218→
219→  const mainWidthStyle =
220→    hasPanels && columnWidths[0]
221→      ? { flex: `0 0 ${columnWidths[0]}px`, maxWidth: columnWidths[0] }
222→      : undefined;
223→
224→  return (
225→    <div className={`message-detail${hasPanels ? " message-detail--split" : ""}`}>
226→      <div
227→        className={`message-detail__main${focusedColumn === 0 ? " message-detail__main--focused" : ""}`}
228→        style={mainWidthStyle}
229→        onClick={() => setFocusedColumn(0)}
230→      >
231→        <div className="message-detail__header">
232→          <BackButton onClick={onBack} />
233→          <span className="message-detail__title">
234→            {msg.role === "user" ? "User" : msg.role === "claude" ? "Claude" : "System"}
235→          </span>
236→          {model && (
237→            <span style={{ color: modelColor, fontWeight: 600, fontSize: 12 }}>{model}</span>
238→          )}
239→          {msg.subagent_label && (
240→            <span className="detail-item__subagent-badge">{msg.subagent_label}</span>
241→          )}
242→          <span className="message-detail__meta">
243→            {time}
244→            {msg.tokens_raw > 0 && (
245→              <>
246→                {" "}
247→                {"\u00B7"} {formatTokens(msg.tokens_raw)} tok
248→              </>
249→            )}
250→            {msg.duration_ms > 0 && (
251→              <>
252→                {" "}
253→                {"\u00B7"} {formatDuration(msg.duration_ms)}
254→              </>
255→            )}
256→          </span>
257→        </div>
258→
259→        <div className="message-detail__body" ref={bodyRef}>
260→          <div className="message-detail__content">
261→            {msg.content && (
262→              <div className="message-detail__text">
263→                <ReactMarkdown>{msg.content}</ReactMarkdown>
264→              </div>
265→            )}
266→            {hasItems && (
267→              <div className="detail-items">
268→                <div className="detail-items__section-label">Items ({msg.items.length})</div>
269→                {msg.items.map((item, idx) => (
270→                  <DetailItem
271→                    key={`${item.item_type}-${item.tool_name}-${item.tool_summary}-${item.duration_ms}`}
272→                    ref={idx === selectedItem ? scrollRef : undefined}
273→                    item={item}
274→                    index={idx}
275→                    isSelected={idx === selectedItem}
276→                    isExpanded={expandedItems.has(idx)}
277→                    isAgentActive={
278→                      panelStack.length > 0 &&
279→                      panelStack[0].item.agent_id === item.agent_id &&
280→                      !!item.agent_id
281→                    }
282→                    onToggle={handleItemClick}
283→                    onToggleExpand={toggleItem}
284→                    onSelect={setSelectedItem}
285→                  />
286→                ))}
287→              </div>
288→            )}
289→            {ongoing && (
290→              <div className="message-detail__ongoing">
291→                <OngoingDots />
292→              </div>
293→            )}
294→          </div>
295→        </div>
296→      </div>
297→
298→      {panelStack.map((entry, depth) => {
299→        const colWidth = columnWidths[depth + 1];
300→        const widthStyle = colWidth ? { flex: `0 0 ${colWidth}px`, maxWidth: colWidth } : undefined;
301→        const isFocused = focusedColumn === depth + 1;
302→
303→        return (
304→          <PanelColumn
305→            key={entry.key}
306→            entry={entry}
307→            depth={depth}
308→            style={widthStyle}
309→            isFocused={isFocused}
310→            panelStack={panelStack}
311→            onOpenDetail={(detailMsg) => openDetailAt(depth, detailMsg)}
312→            onBackToList={() => backToListAt(depth)}
313→            onOpenSubagent={(item) => openSubagentAt(depth, item)}
314→            onClose={() => closeAt(depth)}
315→            onResize={(w) => setColumnWidth(depth, w)}
316→            onFocus={() => setFocusedColumn(depth + 1)}
317→            onRegisterNav={(nav) => registerPanelNav(depth, nav)}
318→          />
319→        );
320→      })}
321→    </div>
322→  );
323→}
