  7→  return {
  8→    role: "user",
  9→    model: "",
 10→    content: "Hello from user",
 11→    timestamp: "2025-01-01T12:00:00Z",
 12→    thinking_count: 0,
 13→    tool_call_count: 0,
 14→    output_count: 0,
 15→    tokens_raw: 0,
 16→    input_tokens: 0,
 17→    output_tokens: 0,
 18→    cache_read_tokens: 0,
 19→    cache_creation_tokens: 0,
 20→    context_tokens: 0,
 21→    duration_ms: 0,
 22→    items: [],
 23→    last_output: null,
 24→    is_error: false,
 25→    teammate_spawns: 0,
 26→    teammate_messages: 0,
 27→    subagent_label: "",
 28→    ...overrides,
 29→  };
 30→}
 31→
 32→function defaultProps(overrides: Partial<Parameters<typeof MessageList>[0]> = {}) {
 33→  return {
 34→    messages: [] as DisplayMessage[],
 35→    selectedIndex: -1,
 36→    expandedSet: new Set<number>(),
 37→    ongoing: false,
