 55→    ];
 56→    const { container } = render(<MessageList {...defaultProps({ messages })} />);
 57→    const messageEls = container.querySelectorAll(".message");
 58→    // First message (index 0) should appear first in the DOM
 59→    expect(messageEls[0]).toHaveTextContent(/First message/);
 60→    expect(messageEls[1]).toHaveTextContent(/Second message/);
 61→  });
 62→
 63→  it("shows compact separator for compact role", () => {
 64→    const messages = [makeMessage({ role: "compact", content: "--- separator ---" })];
 65→    render(<MessageList {...defaultProps({ messages })} />);
 66→    expect(screen.getByText("--- separator ---")).toBeInTheDocument();
 67→    const { container } = render(<MessageList {...defaultProps({ messages })} />);
 68→    expect(container.querySelector(".compact-separator")).toBeInTheDocument();
 69→  });
 70→
 71→  it("shows correct role labels for user, claude, system", () => {
 72→    const messages = [
 73→      makeMessage({ role: "user", content: "user msg" }),
 74→      makeMessage({ role: "claude", content: "claude msg", model: "claude-sonnet-4-20250514" }),
 75→      makeMessage({ role: "system", content: "system msg" }),
 76→    ];
 77→    render(<MessageList {...defaultProps({ messages })} />);
 78→    expect(screen.getByText("User")).toBeInTheDocument();
 79→    expect(screen.getByText("Claude", { selector: ".message__role" })).toBeInTheDocument();
 80→    expect(screen.getByText("System")).toBeInTheDocument();
 81→  });
 82→
 83→  it("shows model color for claude messages", () => {
 84→    const messages = [
 85→      makeMessage({ role: "claude", content: "Response", model: "claude-sonnet-4-20250514" }),
 86→    ];
 87→    render(<MessageList {...defaultProps({ messages })} />);
 88→    const modelEl = screen.getByText("sonnet4.20250514");
 89→    expect(modelEl).toBeInTheDocument();
 90→    expect(modelEl).toHaveStyle({ color: "#5fafff" }); // modelSonnet color
 91→  });
 92→
 93→  it("clicking selects message; clicking selected toggles expand", () => {
 94→    const onSelect = vi.fn();
 95→    const onToggle = vi.fn();
 96→    const messages = [makeMessage({ content: "Click me" })];
 97→
 98→    // First click: message is not selected, should call onSelect
 99→    const { rerender } = render(
100→      <MessageList {...defaultProps({ messages, selectedIndex: -1, onSelect, onToggle })} />,
101→    );
102→    fireEvent.click(screen.getByText(/Click me/).closest(".message")!);
103→    expect(onSelect).toHaveBeenCalledWith(0);
104→
105→    // Second click: message is already selected, should call onToggle
106→    rerender(<MessageList {...defaultProps({ messages, selectedIndex: 0, onSelect, onToggle })} />);
107→    fireEvent.click(screen.getByText(/Click me/).closest(".message")!);
108→    expect(onToggle).toHaveBeenCalledWith(0);
109→  });
110→
111→  it("double-click opens detail", () => {
112→    const onOpenDetail = vi.fn();
113→    const messages = [makeMessage({ content: "Double click me" })];
114→    render(<MessageList {...defaultProps({ messages, onOpenDetail })} />);
115→    fireEvent.doubleClick(screen.getByText(/Double click me/).closest(".message")!);
116→    expect(onOpenDetail).toHaveBeenCalledWith(0);
117→  });
118→
119→  it("shows stats when tokens present", () => {
120→    const messages = [
121→      makeMessage({ role: "claude", tokens_raw: 5000, model: "claude-sonnet-4-20250514" }),
122→    ];
123→    render(<MessageList {...defaultProps({ messages })} />);
124→    expect(screen.getByText(/5\.0k tok/)).toBeInTheDocument();
125→  });
126→
127→  it("shows stats for tools", () => {
128→    const messages = [
129→      makeMessage({ role: "claude", tool_call_count: 3, model: "claude-sonnet-4-20250514" }),
130→    ];
131→    render(<MessageList {...defaultProps({ messages })} />);
132→    expect(screen.getByText(/3 tools/)).toBeInTheDocument();
133→  });
134→
135→  it("shows stats for thinking", () => {
136→    const messages = [
137→      makeMessage({ role: "claude", thinking_count: 2, model: "claude-sonnet-4-20250514" }),
138→    ];
139→    render(<MessageList {...defaultProps({ messages })} />);
140→    expect(screen.getByText(/2 think/)).toBeInTheDocument();
141→  });
