 16→
 17→/* ─── Panel stack types ─── */
 18→
 19→type PanelEntry =
 20→  | { kind: "agent-list"; item: DisplayItem; key: string }
 21→  | { kind: "agent-detail"; item: DisplayItem; msg: DisplayMessage; key: string };
 22→
 23→/** Imperative handle exposed by each navigable column */
 24→interface ColumnNav {
 25→  moveUp: () => void;
 26→  moveDown: () => void;
 27→  toggle: () => void;
 28→  enter: () => void;
 29→  itemCount: () => number;
 30→}
 31→
 32→interface MessageDetailProps {
 33→  message: DisplayMessage;
 34→  ongoing?: boolean;
 35→  onBack: () => void;
 36→}
 37→
 38→export function MessageDetail({ message: msg, ongoing, onBack }: MessageDetailProps) {
 39→  const { set: expandedItems, toggle: toggleItem } = useToggleSet();
 40→  const [selectedItem, setSelectedItem] = useState(0);
 41→  const scrollRef = useScrollToSelected(selectedItem);
 42→  const [panelStack, setPanelStack] = useState<PanelEntry[]>([]);
 43→  const [columnWidths, setColumnWidths] = useState<(number | null)[]>([null]);
 44→  const [focusedColumn, setFocusedColumn] = useState(0); // 0 = main, 1+ = panel index + 1
 45→  const bodyRef = useRef<HTMLDivElement>(null);
 46→  const savedScroll = useRef<number | null>(null);
 47→  const panelRefs = useRef<Map<number, ColumnNav>>(new Map());
 48→
 49→  useLayoutEffect(() => {
 50→    if (savedScroll.current != null && bodyRef.current) {
 51→      bodyRef.current.scrollTop = savedScroll.current;
 52→      savedScroll.current = null;
 53→    }
 54→  }, [panelStack.length]);
 55→
 56→  const model = msg.model ? shortModel(msg.model) : "";
 57→  const modelColor = msg.model ? getModelColor(msg.model) : undefined;
 58→  const time = formatExactTime(msg.timestamp);
 59→  const hasItems = msg.items.length > 0;
 60→  const hasPanels = panelStack.length > 0;
 61→
 62→  // Stack manipulation
 63→  const openSubagentFromMain = useCallback((item: DisplayItem) => {
 64→    if (bodyRef.current) {
 65→      savedScroll.current = bodyRef.current.scrollTop;
 66→    }
 67→    setPanelStack((prev) => {
 68→      if (
 69→        prev.length === 1 &&
 70→        prev[0].kind === "agent-list" &&
 71→        prev[0].item.agent_id === item.agent_id
 72→      ) {
 73→        return [];
 74→      }
 75→      return [{ kind: "agent-list", item, key: item.agent_id || `panel-0` }];
 76→    });
 77→    setColumnWidths((prev) => [prev[0]]);
 78→    setFocusedColumn(1);
 79→  }, []);
 80→
 81→  const openSubagentAt = useCallback((depth: number, item: DisplayItem) => {
 82→    setPanelStack((prev) => {
 83→      const next = prev.slice(0, depth + 1);
 84→      next.push({ kind: "agent-list", item, key: item.agent_id || `panel-${depth + 1}` });
 85→      return next;
 86→    });
 87→    setColumnWidths((prev) => prev.slice(0, depth + 2));
 88→    setFocusedColumn(depth + 2);
 89→  }, []);
 90→
 91→  const openDetailAt = useCallback((depth: number, detailMsg: DisplayMessage) => {
 92→    setPanelStack((prev) => {
 93→      const entry = prev[depth];
 94→      if (!entry || entry.kind !== "agent-list") return prev;
 95→      const next = prev.slice(0, depth);
 96→      next.push({
 97→        kind: "agent-detail",
 98→        item: entry.item,
 99→        msg: detailMsg,
100→        key: entry.key + ":detail",
101→      });
102→      return next;
103→    });
104→  }, []);
105→
106→  const backToListAt = useCallback((depth: number) => {
107→    setPanelStack((prev) => {
108→      const entry = prev[depth];
109→      if (!entry || entry.kind !== "agent-detail") return prev;
110→      const next = prev.slice(0, depth);
111→      next.push({
112→        kind: "agent-list",
113→        item: entry.item,
114→        key: entry.item.agent_id || `panel-${depth}`,
115→      });
116→      return next;
117→    });
118→  }, []);
119→
120→  const closeAt = useCallback((depth: number) => {
121→    setPanelStack((prev) => prev.slice(0, depth));
122→    setColumnWidths((prev) => prev.slice(0, depth + 1));
123→    setFocusedColumn((prev) => Math.min(prev, depth));
124→  }, []);
125→
126→  const setColumnWidth = useCallback((colIndex: number, width: number) => {
127→    setColumnWidths((prev) => {
128→      const next = [...prev];
129→      while (next.length <= colIndex) next.push(null);
130→      next[colIndex] = width;
131→      return next;
132→    });
133→  }, []);
134→
135→  const handleItemClick = (index: number, item: DisplayItem) => {
136→    setSelectedItem(index);
137→    setFocusedColumn(0);
138→    if (item.subagent_messages.length > 0) {
139→      openSubagentFromMain(item);
140→    } else {
141→      toggleItem(index);
142→    }
143→  };
144→
145→  const registerPanelNav = useCallback((depth: number, nav: ColumnNav | null) => {
146→    if (nav) {
147→      panelRefs.current.set(depth, nav);
148→    } else {
149→      panelRefs.current.delete(depth);
150→    }
151→  }, []);
152→
153→  // Single keyboard handler for all columns
154→  const detailKeyMap: Record<string, () => void> = {};
155→
156→  // Navigation: j/k/ArrowDown/ArrowUp/Tab/Enter dispatch to the focused column
157→  const moveDown = () => {
158→    if (focusedColumn === 0) {
159→      setSelectedItem((i) => Math.min(i + 1, msg.items.length - 1));
160→    } else {
161→      const nav = panelRefs.current.get(focusedColumn - 1);
162→      nav?.moveDown();
163→    }
164→  };
165→  const moveUp = () => {
166→    if (focusedColumn === 0) {
167→      setSelectedItem((i) => Math.max(i - 1, 0));
168→    } else {
169→      const nav = panelRefs.current.get(focusedColumn - 1);
170→      nav?.moveUp();
171→    }
172→  };
173→  detailKeyMap["j"] = moveDown;
174→  detailKeyMap["ArrowDown"] = moveDown;
175→  detailKeyMap["k"] = moveUp;
176→  detailKeyMap["ArrowUp"] = moveUp;
177→  detailKeyMap["Tab"] = () => {
178→    if (focusedColumn === 0) {
179→      const item = msg.items[selectedItem];
180→      if (item) handleItemClick(selectedItem, item);
181→    } else {
182→      const nav = panelRefs.current.get(focusedColumn - 1);
183→      nav?.toggle();
184→    }
185→  };
186→  detailKeyMap["Enter"] = () => {
187→    if (focusedColumn === 0) {
188→      const item = msg.items[selectedItem];
189→      if (item && item.subagent_messages.length > 0) {
190→        openSubagentFromMain(item);
191→      } else if (item) {
192→        toggleItem(selectedItem);
193→      }
194→    } else {
195→      const nav = panelRefs.current.get(focusedColumn - 1);
196→      nav?.enter();
197→    }
198→  };
199→
200→  // h/l or ArrowLeft/ArrowRight to switch focused column
201→  detailKeyMap["h"] = () => setFocusedColumn((c) => Math.max(0, c - 1));
202→  detailKeyMap["ArrowLeft"] = () => setFocusedColumn((c) => Math.max(0, c - 1));
203→  detailKeyMap["l"] = () => setFocusedColumn((c) => Math.min(panelStack.length, c + 1));
204→  detailKeyMap["ArrowRight"] = () => setFocusedColumn((c) => Math.min(panelStack.length, c + 1));
205→
206→  // q = go back to list
207→  detailKeyMap["q"] = onBack;
208→  // Escape = close rightmost panel, or go back
209→  detailKeyMap["Escape"] = () => {
210→    if (panelStack.length > 0) {
211→      closeAt(panelStack.length - 1);
212→    } else {
213→      onBack();
214→    }
215→  };
216→
217→  useKeyboard(detailKeyMap);
218→
219→  const mainWidthStyle =
220→    hasPanels && columnWidths[0]
221→      ? { flex: `0 0 ${columnWidths[0]}px`, maxWidth: columnWidths[0] }
222→      : undefined;
223→
224→  return (
225→    <div className={`message-detail${hasPanels ? " message-detail--split" : ""}`}>
226→      <div
227→        className={`message-detail__main${focusedColumn === 0 ? " message-detail__main--focused" : ""}`}
228→        style={mainWidthStyle}
229→        onClick={() => setFocusedColumn(0)}
230→      >
231→        <div className="message-detail__header">
232→          <BackButton onClick={onBack} />
233→          <span className="message-detail__title">
234→            {msg.role === "user" ? "User" : msg.role === "claude" ? "Claude" : "System"}
235→          </span>
236→          {model && (
237→            <span style={{ color: modelColor, fontWeight: 600, fontSize: 12 }}>{model}</span>
238→          )}
239→          {msg.subagent_label && (
240→            <span className="detail-item__subagent-badge">{msg.subagent_label}</span>
241→          )}
242→          <span className="message-detail__meta">
243→            {time}
244→            {msg.tokens_raw > 0 && (
245→              <>
246→                {" "}
247→                {"\u00B7"} {formatTokens(msg.tokens_raw)} tok
248→              </>
249→            )}
250→            {msg.duration_ms > 0 && (
251→              <>
252→                {" "}
253→                {"\u00B7"} {formatDuration(msg.duration_ms)}
254→              </>
255→            )}
256→          </span>
257→        </div>
258→
259→        <div className="message-detail__body" ref={bodyRef}>
260→          <div className="message-detail__content">
261→            {msg.content && (
262→              <div className="message-detail__text">
263→                <ReactMarkdown>{msg.content}</ReactMarkdown>
264→              </div>
265→            )}
266→            {hasItems && (
267→              <div className="detail-items">
268→                <div className="detail-items__section-label">Items ({msg.items.length})</div>
269→                {msg.items.map((item, idx) => (
270→                  <DetailItem
271→                    key={`${item.item_type}-${item.tool_name}-${item.tool_summary}-${item.duration_ms}`}
272→                    ref={idx === selectedItem ? scrollRef : undefined}
273→                    item={item}
274→                    index={idx}
275→                    isSelected={idx === selectedItem}
276→                    isExpanded={expandedItems.has(idx)}
277→                    isAgentActive={
278→                      panelStack.length > 0 &&
279→                      panelStack[0].item.agent_id === item.agent_id &&
280→                      !!item.agent_id
281→                    }
282→                    onToggle={handleItemClick}
283→                    onToggleExpand={toggleItem}
284→                    onSelect={setSelectedItem}
285→                  />
286→                ))}
287→              </div>
288→            )}
289→            {ongoing && (
290→              <div className="message-detail__ongoing">
291→                <OngoingDots />
292→              </div>
293→            )}
294→          </div>
295→        </div>
296→      </div>
297→
298→      {panelStack.map((entry, depth) => {
299→        const colWidth = columnWidths[depth + 1];
300→        const widthStyle = colWidth ? { flex: `0 0 ${colWidth}px`, maxWidth: colWidth } : undefined;
301→        const isFocused = focusedColumn === depth + 1;
302→
303→        return (
304→          <PanelColumn
305→            key={entry.key}
306→            entry={entry}
307→            depth={depth}
308→            style={widthStyle}
309→            isFocused={isFocused}
310→            panelStack={panelStack}
311→            onOpenDetail={(detailMsg) => openDetailAt(depth, detailMsg)}
312→            onBackToList={() => backToListAt(depth)}
313→            onOpenSubagent={(item) => openSubagentAt(depth, item)}
314→            onClose={() => closeAt(depth)}
315→            onResize={(w) => setColumnWidth(depth, w)}
316→            onFocus={() => setFocusedColumn(depth + 1)}
317→            onRegisterNav={(nav) => registerPanelNav(depth, nav)}
318→          />
319→        );
320→      })}
321→    </div>
322→  );
323→}
324→
325→/* ─── PanelColumn: renders ResizeHandle + either list or detail ─── */
326→
327→interface PanelColumnProps {
328→  entry: PanelEntry;
329→  depth: number;
330→  style?: React.CSSProperties;
331→  isFocused: boolean;
332→  panelStack: PanelEntry[];
333→  onOpenDetail: (msg: DisplayMessage) => void;
334→  onBackToList: () => void;
335→  onOpenSubagent: (item: DisplayItem) => void;
336→  onClose: () => void;
337→  onResize: (width: number) => void;
338→  onFocus: () => void;
339→  onRegisterNav: (nav: ColumnNav | null) => void;
340→}
341→
342→function PanelColumn({
343→  entry,
344→  depth,
345→  style,
346→  isFocused,
347→  panelStack,
348→  onOpenDetail,
349→  onBackToList,
350→  onOpenSubagent,
351→  onClose,
352→  onResize,
353→  onFocus,
354→  onRegisterNav,
355→}: PanelColumnProps) {
356→  return (
357→    <>
358→      <ResizeHandle onResize={onResize} />
359→      {entry.kind === "agent-list" ? (
360→        <AgentListColumn
361→          item={entry.item}
362→          style={style}
363→          isFocused={isFocused}
364→          onOpenDetail={onOpenDetail}
365→          onClose={onClose}
366→          onFocus={onFocus}
367→          onRegisterNav={onRegisterNav}
368→        />
369→      ) : (
370→        <AgentDetailColumn
371→          item={entry.item}
372→          msg={entry.msg}
373→          style={style}
374→          isFocused={isFocused}
375→          depth={depth}
376→          panelStack={panelStack}
377→          onOpenSubagent={onOpenSubagent}
378→          onBack={onBackToList}
379→          onClose={onClose}
380→          onFocus={onFocus}
381→          onRegisterNav={onRegisterNav}
382→        />
383→      )}
384→    </>
385→  );
386→}
387→
388→/* ─── AgentListColumn: shows agent header + message list ─── */
389→
390→interface AgentListColumnProps {
391→  item: DisplayItem;
392→  style?: React.CSSProperties;
393→  isFocused: boolean;
394→  onOpenDetail: (msg: DisplayMessage) => void;
395→  onClose: () => void;
396→  onFocus: () => void;
397→  onRegisterNav: (nav: ColumnNav | null) => void;
398→}
399→
400→function AgentListColumn({
401→  item,
402→  style,
403→  isFocused,
404→  onOpenDetail,
405→  onClose,
406→  onFocus,
407→  onRegisterNav,
408→}: AgentListColumnProps) {
409→  const messages = item.subagent_messages;
410→  const [selectedMsg, setSelectedMsg] = useState(messages.length - 1);
411→  const { set: expandedSet, toggle: toggleMsg } = useToggleSet();
412→  const listRef = useRef<HTMLDivElement>(null);
413→  const selectedRef = useScrollToSelected(selectedMsg);
414→  const panelColor = item.team_color ? getTeamColor(item.team_color) : undefined;
415→
416→  const handleClick = useCallback(
417→    (index: number) => {
418→      onFocus();
419→      if (selectedMsg === index) {
420→        toggleMsg(index);
421→      } else {
422→        setSelectedMsg(index);
423→      }
424→    },
425→    [selectedMsg, toggleMsg, onFocus],
426→  );
427→
428→  // Expose navigation to parent via callback ref
429→  const navRef = useRef<ColumnNav>({
430→    moveUp: () => setSelectedMsg((i) => Math.max(i - 1, 0)),
431→    moveDown: () => setSelectedMsg((i) => Math.min(i + 1, messages.length - 1)),
432→    toggle: () => toggleMsg(selectedMsg),
433→    enter: () => {
434→      if (messages[selectedMsg]) onOpenDetail(messages[selectedMsg]);
435→    },
436→    itemCount: () => messages.length,
437→  });
438→  navRef.current.moveUp = () => setSelectedMsg((i) => Math.max(i - 1, 0));
439→  navRef.current.moveDown = () => setSelectedMsg((i) => Math.min(i + 1, messages.length - 1));
440→  navRef.current.toggle = () => toggleMsg(selectedMsg);
441→  navRef.current.enter = () => {
442→    if (messages[selectedMsg]) onOpenDetail(messages[selectedMsg]);
443→  };
444→  navRef.current.itemCount = () => messages.length;
445→
446→  // Register/unregister nav on mount/unmount
447→  useLayoutEffect(() => {
448→    onRegisterNav(navRef.current);
449→    return () => onRegisterNav(null);
450→  }, [onRegisterNav]);
451→
452→  const ordered = useMemo(() => {
453→    const indices: number[] = [];
454→    for (let i = 0; i < messages.length; i++) indices.push(i);
455→    return indices;
456→  }, [messages.length]);
457→
458→  return (
459→    <div
460→      className={`agent-panel${isFocused ? " agent-panel--focused" : ""}`}
461→      style={
462→        {
463→          ...(panelColor ? { background: `${panelColor}08` } : {}),
464→          ...style,
465→        } as React.CSSProperties
466→      }
467→      onClick={onFocus}
468→    >
469→      <AgentPanelHeader item={item} panelColor={panelColor} onClose={onClose} />
470→      <div className="agent-panel__content">
471→        <div className="agent-panel__list" ref={listRef}>
472→          {ordered.map((i) => {
473→            const msg = messages[i];
474→            if (msg.role === "compact") {
475→              return (
476→                <div key={i} className="compact-separator">
477→                  <div className="compact-separator__line">
478→                    <span className="compact-separator__rule" />
479→                    <span>{msg.content}</span>
480→                    <span className="compact-separator__rule" />
481→                  </div>
482→                </div>
483→              );
484→            }
485→            const isSelected = i === selectedMsg;
486→            const isExpanded = expandedSet.has(i);
487→            const isLast = i === messages.length - 1;
488→            return (
489→              <MessageItem
490→                key={i}
491→                ref={isSelected ? selectedRef : undefined}
492→                message={msg}
493→                index={i}
494→                isSelected={isSelected}
495→                isExpanded={isExpanded}
496→                isOngoing={isLast && item.subagent_ongoing}
497→                onClick={handleClick}
498→                onOpenDetail={(idx) => onOpenDetail(messages[idx])}
499→              />
500→            );
501→          })}
502→        </div>
503→      </div>
504→    </div>
505→  );
506→}
507→
508→/* ─── AgentDetailColumn: shows a single message's detail items ─── */
509→
510→interface AgentDetailColumnProps {
511→  item: DisplayItem;
512→  msg: DisplayMessage;
513→  style?: React.CSSProperties;
514→  isFocused: boolean;
515→  depth: number;
516→  panelStack: PanelEntry[];
517→  onOpenSubagent: (item: DisplayItem) => void;
518→  onBack: () => void;
519→  onClose: () => void;
520→  onFocus: () => void;
521→  onRegisterNav: (nav: ColumnNav | null) => void;
522→}
523→
524→function AgentDetailColumn({
525→  item,
526→  msg,
527→  style,
528→  isFocused,
529→  depth,
530→  panelStack,
531→  onOpenSubagent,
532→  onBack,
533→  onClose,
534→  onFocus,
535→  onRegisterNav,
536→}: AgentDetailColumnProps) {
537→  const { set: expandedItems, toggle: toggleItem } = useToggleSet();
538→  const [selectedItem, setSelectedItem] = useState(0);
539→  const scrollRef = useScrollToSelected(selectedItem);
540→  const panelColor = item.team_color ? getTeamColor(item.team_color) : undefined;
541→
542→  const model = msg.model ? shortModel(msg.model) : "";
543→  const modelColor = msg.model ? getModelColor(msg.model) : undefined;
544→  const time = formatExactTime(msg.timestamp);
545→  const hasItems = msg.items.length > 0;
546→
547→  // Check if a deeper panel is open for a given agent_id
548→  const activeAgentId = depth + 1 < panelStack.length ? panelStack[depth + 1].item.agent_id : null;
549→
550→  const handleItemClick = (index: number, clickedItem: DisplayItem) => {
551→    onFocus();
552→    setSelectedItem(index);
553→    if (clickedItem.subagent_messages.length > 0) {
554→      onOpenSubagent(clickedItem);
555→    } else {
556→      toggleItem(index);
557→    }
558→  };
559→
560→  // Expose navigation to parent via callback ref
561→  const navRef = useRef<ColumnNav>({
562→    moveUp: () => {},
563→    moveDown: () => {},
564→    toggle: () => {},
565→    enter: () => {},
566→    itemCount: () => msg.items.length,
567→  });
568→  navRef.current.moveUp = () => setSelectedItem((i) => Math.max(i - 1, 0));
569→  navRef.current.moveDown = () => setSelectedItem((i) => Math.min(i + 1, msg.items.length - 1));
570→  navRef.current.toggle = () => {
571→    const it = msg.items[selectedItem];
572→    if (it) handleItemClick(selectedItem, it);
573→  };
574→  navRef.current.enter = () => {
575→    const it = msg.items[selectedItem];
576→    if (it && it.subagent_messages.length > 0) {
577→      onOpenSubagent(it);
578→    } else if (it) {
579→      toggleItem(selectedItem);
580→    }
581→  };
582→  navRef.current.itemCount = () => msg.items.length;
583→
584→  useLayoutEffect(() => {
585→    onRegisterNav(navRef.current);
586→    return () => onRegisterNav(null);
587→  }, [onRegisterNav]);
588→
589→  return (
590→    <div
591→      className={`agent-panel${isFocused ? " agent-panel--focused" : ""}`}
592→      style={
593→        {
594→          ...(panelColor ? { background: `${panelColor}08` } : {}),
595→          ...style,
596→        } as React.CSSProperties
597→      }
598→      onClick={onFocus}
599→    >
600→      <AgentPanelHeader item={item} panelColor={panelColor} onClose={onClose} />
601→      <div className="agent-panel__content">
602→        <div className="message-detail__header" style={{ borderBottom: "1px solid var(--border)" }}>
603→          <BackButton onClick={onBack} />
604→          <span className="message-detail__title">
605→            {msg.role === "user" ? "User" : msg.role === "claude" ? "Claude" : "System"}
606→          </span>
607→          {model && (
608→            <span style={{ color: modelColor, fontWeight: 600, fontSize: 12 }}>{model}</span>
609→          )}
610→          <span className="message-detail__meta">
611→            {time}
612→            {msg.tokens_raw > 0 && (
613→              <>
614→                {" "}
615→                {"\u00B7"} {formatTokens(msg.tokens_raw)} tok
616→              </>
617→            )}
618→          </span>
619→        </div>
620→        <div className="message-detail__body">
621→          <div className="message-detail__content">
622→            {msg.content && (
623→              <div className="message-detail__text">
624→                <ReactMarkdown>{msg.content}</ReactMarkdown>
625→              </div>
626→            )}
627→            {hasItems && (
628→              <div className="detail-items">
629→                <div className="detail-items__section-label">Items ({msg.items.length})</div>
630→                {msg.items.map((di, idx) => (
631→                  <DetailItem
632→                    key={`${di.item_type}-${di.tool_name}-${di.tool_summary}-${di.duration_ms}`}
633→                    ref={idx === selectedItem ? scrollRef : undefined}
634→                    item={di}
635→                    index={idx}
636→                    isSelected={idx === selectedItem}
637→                    isExpanded={expandedItems.has(idx)}
638→                    isAgentActive={activeAgentId === di.agent_id && !!di.agent_id}
639→                    onToggle={handleItemClick}
640→                    onToggleExpand={toggleItem}
641→                    onSelect={setSelectedItem}
642→                  />
643→                ))}
644→              </div>
645→            )}
646→            {item.subagent_ongoing && (
647→              <div className="message-detail__ongoing">
648→                <OngoingDots />
649→              </div>
650→            )}
651→          </div>
652→        </div>
653→      </div>
654→    </div>
655→  );
656→}
657→
658→/* ─── Shared agent panel header ─── */
659→
660→function AgentPanelHeader({
661→  item,
662→  panelColor,
663→  onClose,
664→}: {
665→  item: DisplayItem;
666→  panelColor?: string;
667→  onClose: () => void;
668→}) {
669→  return (
670→    <div
671→      className="agent-panel__header"
672→      style={panelColor ? { background: `${panelColor}10` } : undefined}
673→    >
674→      <button className="agent-panel__close" onClick={onClose}>
675→        <IoMdCloseCircle className="icon--close" />
676→      </button>
677→      <span className="agent-panel__icon">
678→        <ClaudeIcon />
679→      </span>
680→      <span className="agent-panel__type" style={panelColor ? { color: panelColor } : undefined}>
681→        {item.subagent_type || item.tool_name || "Subagent"}
682→      </span>
683→      {(item.subagent_desc || item.tool_summary) && (
684→        <span className="agent-panel__desc">{item.subagent_desc || item.tool_summary}</span>
685→      )}
686→      {item.agent_id && <span className="agent-panel__id">{item.agent_id}</span>}
687→      <span className="agent-panel__stats">
688→        {item.duration_ms > 0 && <span>{formatDuration(item.duration_ms)}</span>}
689→      </span>
690→    </div>
691→  );
692→}
