 1→import { useRef, useEffect } from "react";
 2→
 3→/**
 4→ * Auto-scrolls a container to the bottom when `itemCount` increases,
 5→ * but only if the user is already near the bottom (within `threshold` px).
 6→ */
 7→export function useAutoScroll<T extends HTMLElement>(itemCount: number, threshold = 150) {
 8→  const ref = useRef<T>(null);
 9→  const prevCountRef = useRef(itemCount);
10→
11→  useEffect(() => {
12→    const el = ref.current;
13→    if (el && itemCount > prevCountRef.current) {
14→      const isNearBottom = el.scrollHeight - el.scrollTop - el.clientHeight < threshold;
15→      if (isNearBottom) {
16→        el.scrollTop = el.scrollHeight;
